const UPDATE_THIS_MESSAGE_BODY = "UPDATE-THIS-MESSAGE-BODY";
const SEND_THIS_MESSAGE = "SEND-THIS-MESSAGE";

let initialState = {
  dialogs: [
    { id: 1, name: "Dimych" },
    { id: 2, name: "Andrew" },
    { id: 3, name: "Sveta" }],
  messages: [
    { id: 1, message: "Hi" },
    { id: 2, message: "How are you?" },
    { id: 3, message: "Yo" }],
  newMessageBody: ""  
}

const mydialogsReducer = (state = initialState, action) => {

  switch (action.type) {
    case UPDATE_THIS_MESSAGE_BODY:
      return {
        ...state,
        newMessageBody: action.body
      };
    case SEND_THIS_MESSAGE:
      let body = state.newMessageBody;
      return {
        ...state,
        newMessageBody: "",
        messages: [...state.messages, { id: 6, message: body }]
      };
      default:
      return state;
  } 
    }
    export const updateNewMessageBodyCreator = (body) => ({ type: UPDATE_THIS_MESSAGE_BODY, body });

export const sendMessageCreator = () => ({ type: SEND_THIS_MESSAGE });

export default mydialogsReducer;