let initialState = {
  status: "Hello Newsfff"
};

const newsReducer = (state = initialState, action) => {
  switch (action.type) {
    case "SET_NEWS_STATUS":
      return {
        ...state,
        status: action.status
      };

    default:
      return state;
  }
};

export const setNewsStatus = (status) => ({
    type: 'SET_NEWS_STATUS',
    status
});



export default newsReducer;