import React, { Component } from "react";
import "./App.css";
import Navbar from "./components/Navbar/Navbar";
import { Routes, Route, Navigate } from "react-router-dom";
//import DialogsContainer from "./components/Dialogs/DialogsContainer";
import UserContainer from "./components/Users/UserContainer";
import OthersContainer from "./components/Others/OthersContainer";
//simport ProfileContainer from "./components/Profile/ProfileContainer";
import HeaderContainer from "./components/Header/HeaderContainer";
import LoginPage from "./components/Login/Login";
import NewsContainer from "./components/News/NewsContainer";
import MyDialogsContainer from "./components/myDialogs/myDialogsContainer";
import { connect } from "react-redux";
import { withRouter } from "./hoc/withRouter";
import { compose } from "redux";
import Preloader from "./components/common/Preloader/Preloader";
import { initializeApp } from "./redux/app-reducer";
import { Provider } from "react-redux";
import { BrowserRouter } from "react-router-dom";
import { withSuspense } from "./hoc/withSuspense";
import store from "./redux/redux-store";
const DialogsContainer = React.lazy(()=>import('./components/Dialogs/DialogsContainer'));
const ProfileContainer = React.lazy(()=>import('./components/Profile/ProfileContainer'));

const SuspendedDialogsContainer = withSuspense(DialogsContainer);
const SuspendedProfileContainer = withSuspense(ProfileContainer);
class App extends Component {

  componentDidMount() {
    this.props.initializeApp(); // 🔥 теперь работает
  }

  render() {   // ❗ ОБЯЗАТЕЛЕН
    if(!this.props.initialized){
      return <Preloader/>
    }
    return (
     
        <div className="app-wrapper">
          <HeaderContainer />
          <Navbar />

        <div className="app-wrapper-content">
  
    <Routes>
      <Route path="/login" element={<LoginPage />} />
      <Route path="/users" element={<UserContainer />} />

      <Route
        path="/profile/:userId"
        element={<SuspendedProfileContainer />}
      />

      <Route path="/profile" element={<SuspendedProfileContainer />} />
      <Route path="/" element={<Navigate to="/profile" />} />

      <Route path="/dialogs" element={<SuspendedDialogsContainer />} />

      <Route path="/news" element={<NewsContainer />} />
      <Route path="/mydialogs" element={<MyDialogsContainer />} />
      <Route path="/others" element={<OthersContainer />} />
    </Routes>
  
</div>
        </div>
   
    );
  }
}

const mapStateToProps = (state) => ({
  initialized:state.app.initialized
});



let AppContainer =   compose(
  withRouter,
  connect(mapStateToProps, { initializeApp  }))(App);

  
  const SamuraiJSApp = (props) =>{
    return (
    <Provider store={store}>
        <BrowserRouter>
          <AppContainer />
        </BrowserRouter>
      </Provider>)
    
  }
export default SamuraiJSApp;



